<span class="line"><span style="color:#CBA6F7;">            let</span><span style="color:#CDD6F4;"> text </span><span style="color:#94E2D5;">=</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#CDD6F4;">source</span><span style="color:#9399B2;">[</span><span style="color:#CDD6F4;">node</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">byte_range</span><span style="color:#9399B2;">()];</span></span>
